import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends a request to spin the slot machine reels.
 * Payload: [ bet ] where bet is clamped 5–25 credits.
 */
export class SlotSpinComposer implements IMessageComposer<number[]> {
    private _data: number[];

    constructor(betAmount: number) {
        // Enforce bet limits: 5–25 credits on client for safety
        const bet = Math.max(5, Math.min(25, betAmount));

        // IMPORTANT: send only the bet, NOT tableId + bet
        this._data = [bet];

        console.log('[SLOTS] Spin sent, bet =', bet);
    }

    public getMessageArray(): number[] {
        return this._data;
    }

    public dispose(): void {
        // no-op
    }
}
